class Solution:
    def combinationSum2(self, candidates: List[int], target: int) -> List[List[int]]:
        candidates.sort()
        ans = []

        def dfs(idx, remain, current_path):
            if remain == 0:
                ans.append(list(current_path))
                return

            for i in range(idx, len(candidates)):
                # Skip duplicates at the same depth
                if i > idx and candidates[i] == candidates[i - 1]:
                    continue

                # Prune the tree if the current candidate exceeds the remaining target
                if candidates[i] > remain:
                    break

                current_path.append(candidates[i])
                dfs(i + 1, remain - candidates[i], current_path)
                current_path.pop()

        dfs(0, target, [])
        return ans
```

