class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        # Precompute frequencies of each digit to achieve O(N) time complexity.
        count = [0] * 10
        for d in digits:
            count[d] += 1

        # Iterate through possible combinations of a, b, and c.
        # This takes at most 9 * 10 * 5 = 450 iterations and generates the valid numbers already sorted.
        return [
            a * 100 + b * 10 + c
            for a in range(1, 10) if count[a]
            for b in range(10) if count[b] > (a == b)
            for c in (0, 2, 4, 6, 8) if count[c] > (a == c) + (b == c)
        ]
