class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        count = [digits.count(i) for i in range(10)]
        ans = []

        for i in range(1, 10):
            if not count[i]:
                continue
            count[i] -= 1

            for j in range(10):
                if not count[j]:
                    continue
                count[j] -= 1

                for k in (0, 2, 4, 6, 8):
                    if count[k]:
                        ans.append(i * 100 + j * 10 + k)

                count[j] += 1
            count[i] += 1

        return ans
```

